svg.script:
(function () {
  var CX = 342, CY = 300;

  // Irregular angles (deg) and distances — intentionally uneven spacing and length
  // Angles: -79, -63, -51, -28, -8, +17, +26, +45, +63, +78
  // Lengths: 148, 218, 172, 245, 190, 228, 195, 158, 225, 152
  var endpointDefs = [
    [370, 155], [441, 106], [450, 166], [558, 185], [530, 274],
    [560, 367], [517, 386], [454, 412], [444, 501], [374, 449]
  ];

  var rays = endpointDefs.map(function (ep, i) {
    var dx = ep[0] - CX, dy = ep[1] - CY;
    return {
      angle:    Math.atan2(dy, dx),
      baseDist: Math.sqrt(dx * dx + dy * dy),
      // Stagger phases so rays don't all pulse in sync
      phase: (i / endpointDefs.length) * Math.PI * 2
    };
  });

  var lines = rays.map(function (_, i) { return document.getElementById('line' + i); });
  var dots  = rays.map(function (_, i) { return document.getElementById('dot'  + i); });

  // Center glow elements
  var haloOuter = document.getElementById('haloOuter');
  var haloInner = document.getElementById('haloInner');
  var burst1    = document.getElementById('burst1');
  var burst2    = document.getElementById('burst2');
  var burst3    = document.getElementById('burst3');

  // Smoothed current positions
  var pos = rays.map(function (r) {
    return { x: CX + r.baseDist * Math.cos(r.angle),
             y: CY + r.baseDist * Math.sin(r.angle) };
  });

  var mouseX = null, mouseY = null;

  // --- Tuning ---
  var PULSE_PERIOD   = 10.0;  // seconds per full in/out cycle
  var PULSE_AMP      = 0.18;  // ±18% of base distance
  var GLOW_PERIOD    = 5.0;   // center glow breathe cycle (different freq feels alive)
  var ATTRACT_RADIUS = 170;
  var ATTRACT_POWER  = 0.65;
  var LERP_NORMAL    = 1.5;
  var LERP_ATTRACT   = 5.0;

  var svg = document.querySelector('svg');
  svg.addEventListener('mousemove', function (e) {
    var r = svg.getBoundingClientRect();
    mouseX = (e.clientX - r.left) * (600 / r.width);
    mouseY = (e.clientY - r.top)  * (600 / r.height);
  });
  svg.addEventListener('mouseleave', function () { mouseX = null; mouseY = null; });

  var lastTs = null, elapsed = 0;

  function frame(ts) {
    if (lastTs === null) lastTs = ts;
    var dt = Math.min((ts - lastTs) / 1000, 0.05);
    lastTs = ts;
    elapsed += dt;

    // --- Center glow pulse (slow breathe, offset phase from rays) ---
    var glowT = 0.5 + 0.5 * Math.sin((elapsed / GLOW_PERIOD) * Math.PI * 2 + 1.2);
    haloOuter.setAttribute('opacity', 0.04 + 0.05 * glowT);
    haloInner.setAttribute('opacity', 0.07 + 0.08 * glowT);
    burst3.setAttribute('opacity',    0.20 + 0.18 * glowT);
    burst2.setAttribute('opacity',    0.45 + 0.25 * glowT);
    burst1.setAttribute('opacity',    0.80 + 0.18 * glowT);

    // --- Ray pulse ---
    var angFreq = (2 * Math.PI) / PULSE_PERIOD;

    // Find closest dot to cursor
    var closestIdx = -1, closestDist = Infinity;
    if (mouseX !== null) {
      for (var i = 0; i < rays.length; i++) {
        var d = Math.sqrt(Math.pow(mouseX - pos[i].x, 2) + Math.pow(mouseY - pos[i].y, 2));
        if (d < closestDist) { closestDist = d; closestIdx = i; }
      }
      if (closestDist > ATTRACT_RADIUS) closestIdx = -1;
    }

    for (var i = 0; i < rays.length; i++) {
      var r = rays[i];
      var pulse = 1 + PULSE_AMP * Math.sin(elapsed * angFreq + r.phase);
      var dist  = r.baseDist * pulse;

      var tx = CX + dist * Math.cos(r.angle);
      var ty = CY + dist * Math.sin(r.angle);

      if (i === closestIdx) {
        var af = ATTRACT_POWER * Math.max(0, 1 - closestDist / ATTRACT_RADIUS);
        tx += (mouseX - tx) * af;
        ty += (mouseY - ty) * af;
      }

      var k = Math.min(1, ((i === closestIdx) ? LERP_ATTRACT : LERP_NORMAL) * dt);
      pos[i].x += (tx - pos[i].x) * k;
      pos[i].y += (ty - pos[i].y) * k;

      lines[i].setAttribute('x2', pos[i].x);
      lines[i].setAttribute('y2', pos[i].y);
      dots[i].setAttribute('cx', pos[i].x);
      dots[i].setAttribute('cy', pos[i].y);
    }

    requestAnimationFrame(frame);
  }

  requestAnimationFrame(frame);
})();
